var ctx = drawingContext; var w = dimensionContext.width; var h = dimensionContext.height;
var g = ctx.createLinearGradient(0,0,0,h);
g.addColorStop(0, '#080a1f');
g.addColorStop(0.4, '#1a1040');
g.addColorStop(1, '#071825');
ctx.fillStyle = g; ctx.fillRect(0,0,w,h);

var centerX = w * 0.5; var horizonY = h * 0.36;

// Tunnel glow and motion haze
var glow = ctx.createRadialGradient(centerX, horizonY, 0, centerX, horizonY, h * 0.9);
glow.addColorStop(0, 'rgba(120,80,255,0.22)');
glow.addColorStop(0.35, 'rgba(45,210,255,0.12)');
glow.addColorStop(1, 'rgba(0,0,0,0)');
ctx.fillStyle = glow; ctx.fillRect(0,0,w,h);

// Glade lane (first-person ski corridor)
ctx.beginPath();
ctx.moveTo(w*0.34, h);
ctx.quadraticCurveTo(w*0.46, h*0.66, w*0.495, horizonY+8);
ctx.quadraticCurveTo(w*0.53, h*0.66, w*0.66, h);
ctx.closePath();
var lane = ctx.createLinearGradient(0,horizonY,w,h);
lane.addColorStop(0,'rgba(170,220,255,0.14)');
lane.addColorStop(0.55,'rgba(120,255,235,0.12)');
lane.addColorStop(1,'rgba(210,120,255,0.16)');
ctx.fillStyle = lane; ctx.fill();

// Hardwoods silhouettes rushing past
var trees = state.trees || [];
for (var t = 0; t < trees.length; t++) {
  var tr = trees[t];
  var py = horizonY + tr.y * (h - horizonY);
  var scale = 0.25 + tr.y * 1.4;
  var xOffset = (0.24 + tr.lane * 0.32) * w * scale;
  var px = centerX + tr.side * xOffset;
  var trunkH = h * tr.h * scale;
  var trunkW = Math.max(1.2, 2.4 * scale);
  var neon = tr.side < 0 ? 'rgba(70,245,255,0.22)' : 'rgba(235,90,255,0.20)';
  ctx.fillStyle = 'rgba(5,20,26,0.88)';
  ctx.fillRect(px - trunkW*0.5, py - trunkH, trunkW, trunkH);
  ctx.strokeStyle = neon; ctx.lineWidth = Math.max(0.6, 1.2 * scale);
  ctx.beginPath(); ctx.moveTo(px, py - trunkH); ctx.lineTo(px, py); ctx.stroke();
  // branch hints
  ctx.beginPath();
  ctx.moveTo(px, py - trunkH*0.62); ctx.lineTo(px + tr.side * 8 * scale, py - trunkH*0.74);
  ctx.moveTo(px, py - trunkH*0.46); ctx.lineTo(px - tr.side * 6 * scale, py - trunkH*0.58);
  ctx.stroke();
}

// Snowflake starfield rushing at viewer
var flakes = state.flakes || [];
ctx.save(); ctx.globalCompositeOperation = 'lighter';
for (var i = 0; i < flakes.length; i++) {
  var f = flakes[i];
  var persp = 1.0 / Math.max(0.05, f.z);
  var sx = centerX + f.x * w * 0.22 * persp;
  var sy = horizonY + f.y * (h - horizonY) * persp * 0.55;
  if (sx < -20 || sx > w+20 || sy < -20 || sy > h+20) continue;
  var len = Math.min(26, 2 + persp * 5.4);
  var wid = Math.min(4.4, 0.5 + persp * 0.7);
  var hue = (i % 2 === 0) ? 190 : 300;
  var a = Math.min(0.95, 0.18 + persp * 0.08);
  ctx.strokeStyle = 'hsla(' + hue + ',100%,78%,' + a.toFixed(3) + ')';
  ctx.lineWidth = wid;
  ctx.beginPath();
  ctx.moveTo(sx, sy);
  ctx.lineTo(sx, sy + len);
  ctx.stroke();
}
ctx.restore();

// Speed lines at periphery
for (var k = 0; k < 22; k++) {
  var side = (k % 2 === 0) ? 0 : w;
  var y = horizonY + (k / 21) * (h - horizonY);
  var lx = side === 0 ? (8 + (k%5)*6) : (w - 8 - (k%5)*6);
  ctx.strokeStyle = side === 0 ? 'rgba(65,240,255,0.14)' : 'rgba(230,80,255,0.12)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(lx, y);
  ctx.lineTo(side === 0 ? lx + 22 : lx - 22, y + 18);
  ctx.stroke();
}
